// SPDX-License-Identifier: LGPL-3.0-or-later
// Test C++ inference for the JAX (.savedmodel) backend with charge_spin input.
// Model and reference data are generated by source/tests/infer/gen_chg_spin.py.
#include <gtest/gtest.h>

#include <algorithm>
#include <cmath>
#include <fstream>
#include <type_traits>
#include <vector>

#include "DeepPot.h"
#include "expected_ref.h"
#include "neighbor_list.h"
#include "test_utils.h"

namespace {
constexpr const char* kRefPath = "../../tests/infer/chg_spin.expected";
constexpr const char* kModelPath = "../../tests/infer/chg_spin.savedmodel";

template <typename T>
double tolerance() {
  return std::is_same<T, double>::value ? 1e-7 : 1e-4;
}
}  // namespace

template <class VALUETYPE>
class TestInferDeepPotChgSpinJAX : public ::testing::Test {
 protected:
  std::vector<VALUETYPE> coord = {12.83, 2.56, 2.18, 12.09, 2.87, 2.74,
                                  0.25,  3.32, 1.68, 3.36,  3.00, 1.81,
                                  3.51,  2.51, 2.60, 4.27,  3.22, 1.56};
  std::vector<int> atype = {0, 1, 1, 0, 1, 1};
  std::vector<VALUETYPE> box = {13., 0., 0., 0., 13., 0., 0., 0., 13.};
  std::vector<double> charge_spin = {1.0, 2.0};
  std::vector<VALUETYPE> expected_force_explicit;
  std::vector<VALUETYPE> expected_force_default;
  std::vector<VALUETYPE> expected_atom_energy_explicit;
  std::vector<VALUETYPE> expected_atom_virial_explicit;
  double expected_energy_explicit = 0.0;
  double expected_energy_default = 0.0;
  deepmd::DeepPot dp;

  void SetUp() override {
#ifndef BUILD_JAX
    GTEST_SKIP() << "Skip because JAX support is not enabled.";
#endif
    std::ifstream model_file(kModelPath);
    if (!model_file.good()) {
      GTEST_SKIP() << "Skip because " << kModelPath << " was not generated.";
    }
    dp.init(kModelPath);

    deepmd_test::ExpectedRef ref;
    ref.load(kRefPath);
    expected_atom_energy_explicit =
        ref.get<VALUETYPE>("explicit", "expected_e");
    expected_atom_virial_explicit =
        ref.get<VALUETYPE>("explicit", "expected_v");
    expected_force_explicit = ref.get<VALUETYPE>("explicit", "expected_f");
    expected_force_default = ref.get<VALUETYPE>("default", "expected_f");
    const auto expected_atom_energy_default =
        ref.get<VALUETYPE>("default", "expected_e");
    for (const auto value : expected_atom_energy_explicit) {
      expected_energy_explicit += value;
    }
    for (const auto value : expected_atom_energy_default) {
      expected_energy_default += value;
    }
  }

  void expect_force(const std::vector<VALUETYPE>& actual,
                    const std::vector<VALUETYPE>& expected) const {
    ASSERT_EQ(actual.size(), expected.size());
    for (std::size_t ii = 0; ii < actual.size(); ++ii) {
      EXPECT_NEAR(actual[ii], expected[ii], tolerance<VALUETYPE>());
    }
  }
};

TYPED_TEST_SUITE(TestInferDeepPotChgSpinJAX, ValueTypes);

TYPED_TEST(TestInferDeepPotChgSpinJAX, explicit_and_default_inputs) {
  using VALUETYPE = TypeParam;
  double energy;
  std::vector<VALUETYPE> force, virial;

  this->dp.compute(energy, force, virial, this->coord, this->atype, this->box,
                   {}, {}, this->charge_spin);
  EXPECT_NEAR(energy, this->expected_energy_explicit, tolerance<VALUETYPE>());
  this->expect_force(force, this->expected_force_explicit);

  this->dp.compute(energy, force, virial, this->coord, this->atype, this->box);
  EXPECT_NEAR(energy, this->expected_energy_default, tolerance<VALUETYPE>());
  this->expect_force(force, this->expected_force_default);
}

TYPED_TEST(TestInferDeepPotChgSpinJAX, atomic_output_overload) {
  using VALUETYPE = TypeParam;
  double energy;
  std::vector<VALUETYPE> force, virial, atom_energy, atom_virial;

  this->dp.compute(energy, force, virial, atom_energy, atom_virial, this->coord,
                   this->atype, this->box, {}, {}, this->charge_spin);

  EXPECT_NEAR(energy, this->expected_energy_explicit, tolerance<VALUETYPE>());
  this->expect_force(force, this->expected_force_explicit);
  this->expect_force(atom_energy, this->expected_atom_energy_explicit);
  this->expect_force(atom_virial, this->expected_atom_virial_explicit);
}

TYPED_TEST(TestInferDeepPotChgSpinJAX, broadcasts_one_frame_input) {
  using VALUETYPE = TypeParam;
  auto coord = this->coord;
  coord.insert(coord.end(), this->coord.begin(), this->coord.end());
  auto box = this->box;
  box.insert(box.end(), this->box.begin(), this->box.end());
  std::vector<double> energy;
  std::vector<VALUETYPE> force, virial;

  this->dp.compute(energy, force, virial, coord, this->atype, box, {}, {},
                   this->charge_spin);

  ASSERT_EQ(energy.size(), 2u);
  EXPECT_NEAR(energy[0], this->expected_energy_explicit,
              tolerance<VALUETYPE>());
  EXPECT_NEAR(energy[1], this->expected_energy_explicit,
              tolerance<VALUETYPE>());
  ASSERT_EQ(force.size(), 2 * this->expected_force_explicit.size());
  for (std::size_t ii = 0; ii < force.size(); ++ii) {
    EXPECT_NEAR(
        force[ii],
        this->expected_force_explicit[ii %
                                      this->expected_force_explicit.size()],
        tolerance<VALUETYPE>());
  }
}

TYPED_TEST(TestInferDeepPotChgSpinJAX, rejects_invalid_input_size) {
  using VALUETYPE = TypeParam;
  double energy;
  std::vector<VALUETYPE> force, virial;
  const std::vector<double> invalid_charge_spin = {1.0, 2.0, 3.0};

  EXPECT_THROW(this->dp.compute(energy, force, virial, this->coord, this->atype,
                                this->box, {}, {}, invalid_charge_spin),
               deepmd::deepmd_exception);
}

TYPED_TEST(TestInferDeepPotChgSpinJAX, neighbor_list_overload) {
  using VALUETYPE = TypeParam;
  const int natoms = static_cast<int>(this->atype.size());
  std::vector<std::vector<int>> nlist_data = {{1, 2, 3, 4, 5}, {0, 2, 3, 4, 5},
                                              {0, 1, 3, 4, 5}, {0, 1, 2, 4, 5},
                                              {0, 1, 2, 3, 5}, {0, 1, 2, 3, 4}};
  std::vector<int> ilist(natoms), numneigh(natoms);
  std::vector<int*> firstneigh(natoms);
  deepmd::InputNlist inlist(natoms, ilist.data(), numneigh.data(),
                            firstneigh.data());
  convert_nlist(inlist, nlist_data);
  double energy;
  std::vector<VALUETYPE> force, virial;

  this->dp.compute(energy, force, virial, this->coord, this->atype, {}, 0,
                   inlist, 0, {}, {}, this->charge_spin);

  deepmd_test::ExpectedRef ref;
  ref.load(kRefPath);
  const auto expected_energy =
      ref.get<VALUETYPE>("nopbc_explicit", "expected_e");
  const auto expected_force =
      ref.get<VALUETYPE>("nopbc_explicit", "expected_f");
  double expected_total_energy = 0.0;
  for (const auto value : expected_energy) {
    expected_total_energy += value;
  }
  EXPECT_NEAR(energy, expected_total_energy, tolerance<VALUETYPE>());
  this->expect_force(force, expected_force);
}
